#include <stdio.h>
#include <math.h>

int countPrimeFactors(int n) {
    int count = 0;
    int factors[100]; // Assuming a number won't have more than 100 distinct prime factors
    int factorIndex = 0;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            int isPrimeFactor = 1;
            for (int j = 0; j < factorIndex; j++) {
                if (factors[j] == i) {
                    isPrimeFactor = 0;
                    break;
                }
            }
            if (isPrimeFactor) {
                factors[factorIndex++] = i;
            }
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        int isPrimeFactor = 1;
        for (int j = 0; j < factorIndex; j++) {
            if (factors[j] == n) {
                isPrimeFactor = 0;
                break;
            }
        }
        if (isPrimeFactor) {
            factors[factorIndex++] = n;
        }
    }
    return factorIndex;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int totalEnergy = 0;
        for (int i = n; i <= m; i++) {
            totalEnergy += countPrimeFactors(i);
        }
        printf("%d\n", totalEnergy);
    }
    return 0;
}

