def count_prime_factors(n):
    count = 0
    factors = set()
    i = 2
    while i * i <= n:
        if n % i == 0:
            if i not in factors:
                factors.add(i)
                count += 1
            n //= i
        else:
            i += 1
    if n > 1:
        count += 1
    return count

