function countPrimeFactors(n) {
    let count = 0;
    let factors = new Set();
    for (let i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            if (!factors.has(i)) {
                factors.add(i);
                count++;
            }
            while (n % i == 0) {
                n = Math.floor(n / i);
            }
        }
    }
    if (n > 1) {
        count++;
    }
    return count;
